class Solution:
    def lastVisitedIntegers(self, nums: List[int]) -> List[int]:
        seen = []
        ans = []
        current_streak = 0

        for num in nums:
            if num == -1:
                current_streak += 1
                k = current_streak
                if k <= len(seen):
                    ans.append(seen[k-1])
                else:
                    ans.append(-1)
            else:
                seen.insert(0, num)
                current_streak = 0

        return ans
